onClick:
{{
appsmith.store.ultimaNCTrabajada

?

(
    storeValue(
        "idNCImpresion",
        appsmith.store.ultimaNCTrabajada
    )

    .then(() => NCImpUltima.run())

    .then(() => NCFactAfectadaImpUltima.run())

    .then(async () => {

        await storeValue(
            "ncImpresion",
            NCImpUltima.data[0]
        );

        await storeValue(
            "fcAfectadaNCImpresion",
            NCFactAfectadaImpUltima.data
        );

        download(

            JS_ImpresionNC.generarHTMLNC(),

            NCImpUltima.data[0]
                .numero_nota_credito
            +
            ".html",

            "text/html"

        );

        showAlert(
            "Nota de crédito cargada e impresa correctamente",
            "success"
        );

    })

)

:

showAlert(
    "No existe una NC creada en esta sesión",
    "warning"
)
}}
